import ast,sys
src=open('src/assay_engine/$f.py').read()
t=ast.parse(src)
for node in ast.walk(t):
    if isinstance(node,ast.ClassDef):
        deco=[ast.unparse(d) for d in node.decorator_list]
        if any('dataclass' in d for d in deco):
            frozen=any('frozen=True' in d for d in deco)
            # fields
            fields=[]
            haspost=False
            for s in node.body:
                if isinstance(s,ast.AnnAssign) and isinstance(s.target,ast.Name):
                    fields.append((s.target.id, ast.unparse(s.annotation)))
                if isinstance(s,ast.FunctionDef) and s.name=='__post_init__':
                    haspost=True
            mapfields=[n for n,a in fields if 'Mapping' in a or 'dict' in a.lower()]
            print(f'  {node.name} frozen={frozen} post_init={haspost} mapping_fields={mapfields}')
"; done
